#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        int x=0, val;
        int *arr = (int*)malloc(N*sizeof(int));
        for(int i=0;i<N;i++){
            scanf("%d", &val);
            arr[i]=val;
            x ^= val;
        }
        int ans = x;
        for(int i=0;i<N;i++){
            int cand = x ^ arr[i];
            if(cand < ans) ans = cand;
        }
        printf("%d\n", ans);
        free(arr);
    }
    return 0;
}

